// 수집 대상 원료 목록 (INCI명)
// 실제 운영 시 Google Sheets나 DB에서 가져오기
const ingredients = [
  'PHENOXYETHANOL',
  'SALICYLIC ACID',
  'NIACINAMIDE',
  'RETINOL',
  'TOCOPHEROL',
  'GLYCERIN',
  'BUTYLENE GLYCOL',
  'SODIUM HYALURONATE',
  'TITANIUM DIOXIDE',
  'ZINC OXIDE',
  'ETHYLHEXYL METHOXYCINNAMATE',
  'BENZOPHENONE-3',
  'METHYLISOTHIAZOLINONE',
  'DIMETHICONE',
  'CETEARYL ALCOHOL',
  'SODIUM LAURYL SULFATE',
  'PROPYLPARABEN',
  'METHYLPARABEN',
  'FRAGRANCE',
  'TRICLOSAN'
];

return ingredients.map(name => ({
  json: {
    inci_name: name,
    search_url: `https://www.ewg.org/skindeep/search/?search=${encodeURIComponent(name)}`
  }
}));

// EWG 검색 결과에서 등급 추출
const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data || item.json.body || '';
  const inci = item.json.inci_name;

  // EWG 등급 패턴 매칭 (HTML에서)
  const scoreMatch = html.match(/data-score="(\d+)"/i) ||
                     html.match(/hazard-score[^>]*>(\d+)/i) ||
                     html.match(/score-(\d+)/i);

  const score = scoreMatch ? parseInt(scoreMatch[1]) : null;

  results.push({
    json: {
      inci_name: inci,
      ewg_score: score,
      ewg_url: item.json.search_url,
      raw_available: html.length > 0,
      collected_at: new Date().toISOString()
    }
  });
}

return results;

